var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계, <color=#ffd34c>클리포트 게임</color>\\n최종 국면","JPN":"裏世界、<color=#ffd34c>クリフォトゲーム</color>\\n最終局面","ENG":"Counterside, <color=#ffd34c>Qliphoth Game</color>\\nFinal battle","TWN":"異界, <color=#ffd34c>逆卡巴拉遊戲</color>\\n最終一戰"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……사람들이 늘고 있군.","JPN":"……人が増えてきているな。","ENG":"...I see that more people are coming.","TWN":"……人越來越多了呢。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반갑네. 모두들.","JPN":"会えてうれしいな、諸君。","ENG":"Greetings, everyone.","TWN":"大家好，很開心見到你們。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 고맙네. 여기까지 애써 줘서.","JPN":"そして感謝する。ここまで頑張ってくれたことに。","ENG":"And thank you. For trying your best so far.","TWN":"還有謝謝你們，費心來到這裡。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들에게 정식으로 소개할 수 있어 무척 기쁘다네.","JPN":"君たちに正式に自己紹介ができて大変うれしく思う。","ENG":"It is a pleasure to introduce myself finally.","TWN":"我很高興能有機會向你們正式地介紹我自己。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 바로 코핀 컴퍼니의 사장이자…….","JPN":"私こそがコフィンカンパニーの社長であり……","ENG":"I am the CEO of Coffin Company...","TWN":"我是科芬公司的老闆……"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국과 오늘날의 관리국을 세운.","JPN":"旧管理局と今の管理局を創設した。","ENG":"And the one who established the old and present Administration.","TWN":"舊管理局和現在的管理局也是我建立的。"},"stage":{"bg":"MS_1102","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자일세.","JPN":"管理者だ。","ENG":"I am the Administrator.","TWN":"我就是管理者。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"subtitle","speaker":null,"text":{"KOREA":"현실세계, 관리국 직할 도시 <color=#ffd34c>그라운드 원</color>","JPN":"現実世界、管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>","ENG":"Normalside, Administration Direct Control City, <color=#ffd34c>Ground One</color>","TWN":"現實世界，管理局直轄市<color=#ffd34c>G1</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"수많은 실패와 역경을 넘어서, 마침내 성공하셨군요.","JPN":"数多の失敗と逆境を乗り越え、ついに成功されたのですね。","ENG":"After overcoming countless failures and adversities, it seems you have finally succeeded.","TWN":"經過無數次的失敗和逆境，你終於成功了。"},"stage":{"bg":"MS_1116","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"……아버지.","JPN":"……父。","ENG":"...Father.","TWN":"……父親。"},"stage":{"bg":"MS_1116","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"현실세계, 관리국 직할 도시 <color=#ffd34c>프론트 베이</color>","JPN":"現実世界、管理局直轄都市<color=#ffd34c>フロントベイ</color>","ENG":"Normalside, Administration Direct Control City, <color=#ffd34c>Front Bay</color>","TWN":"現實世界，管理局直轄市<color=#ffd34c>前灣</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"서, 선장님 저기! 저길 보세요!","JPN":"せ、船長！　あそこを見てください！","ENG":"C-Captain! Over there!","TWN":"船長，那裡！看那邊——！"},"stage":{"bg":"MS_1117","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"프론트베이 해저 대균열에서 정체불명의 빛 기둥이……!!","JPN":"フロントベイ海底の大亀裂から、謎の光の柱が……！！","ENG":"An unidentified pillar of light has appeared from the Grand Dimension Crevice beneath Front Bay...!!","TWN":"海底的大峽谷中出現了奇怪的光柱……！！"},"stage":{"bg":"MS_1117","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩌면 검은 범람이 또 다시 나타나려는 징조 아닐까요?","JPN":"もしかしたら、黒い氾濫がまた現れるんじゃないでしょうか？","ENG":"Is this another omen that the Black Flood will reappear?","TWN":"這是不是說<color=#ffd34c>黑色洪災</color>又要來了～？"},"stage":{"bg":"MS_1117","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"……흐음.","JPN":"……ふーん。","ENG":"...Hmm.","TWN":"……嗯。"},"stage":{"bg":"MS_1117","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"subtitle","speaker":null,"text":{"KOREA":"현실세계, 관리국 직할 도시 <color=#ffd34c>샤레이드</color>","JPN":"現実世界、管理局直轄都市<color=#ffd34c>シャレード</color>","ENG":"Normalside, Administration Direct Control City, <color=#ffd34c>Charade</color>","TWN":"現實世界，管理局直轄市<color=#ffd34c>查雷德</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐예요? 이거 지진 아니에요?","JPN":"な、なに？　これ、地震じゃない？","ENG":"W-what was that? Is this an earthquake?","TWN":"怎，怎麼回事？是地震嗎？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니. 그런 간단한 게 아닌 것 같아.","JPN":"いや。そんな易しいもんじゃなさそうだ。","ENG":"No. I don't think it's that simple.","TWN":"不，好像不是單純的地震。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저기 봐.","JPN":"あそこを見ろ。","ENG":"Look.","TWN":"你看那邊。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저건…. 대균열? 예전에도 저렇게 빛난 적이 있었어요?","JPN":"あれは……大亀裂？　前にもあんな風に光ったことがあったっけ？","ENG":"That's... the Grand Dimension Crevice? Has it ever glowed like that before?","TWN":"那是……大峽谷？以前也有過那樣發光的時候嗎？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"한 번도 없어. 적어도 내가 아는 한에는.","JPN":"一度もない。少なくとも私が知ってる限りは。","ENG":"Never. At least, to my knowledge.","TWN":"從來沒有，至少據我所知是沒有過。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래요……?","JPN":"そう……？","ENG":"Is that so...?","TWN":"是嗎……？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니, 학교 다닐 때 배웠어요.","JPN":"そういえば、学校にいた頃習ったわ。","ENG":"Come to think of it, there's something I learned at school.","TWN":"我想起來了，上學的時候學過。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대균열이 처음 나타났을 때는 지금과 비교할 수 없이 밝았다고.","JPN":"大亀裂が初めて現れた時は、今とは比べ物にならないくらい明るかったって。","ENG":"That, when the Grand Dimension Crevice first appeared, it was unbelievably bright.","TWN":"大峽谷第一次出現的時候特別亮，根本不是現在可以比的。"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"낮밤을 구분할 수 없을 만큼 환해졌다가, 하늘도 땅도 침식체로 온통 뒤덮였다고…….","JPN":"昼夜もわからないくらい明るくなって、空も地上も侵食体だらけになったって……","ENG":"It was so bright that you couldn't tell night from day. And then, the sky and ground were covered with C.O.s...","TWN":"亮到難以區分白天和夜晚的程度，那時天上地下到處都是侵蝕體……"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래? 왜 나는 들은 적이 없냐.","JPN":"ふうん？　聞いたことないな。","ENG":"Really? I've never heard of that.","TWN":"是嗎？為什麼我沒聽說過？"},"stage":{"bg":"CHARADE_005","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……라이카, 세상이 망하는 건 아니겠죠? 지금 망하면 안 되는데.","JPN":"……ライカ、まさか世界が滅亡するんじゃないよね？　今滅亡されると困るんだけど。","ENG":"...Laika, do you think this is the end of the world? I really don't want it to.","TWN":"……萊卡，世界不會要毀滅了吧？現在毀滅可不行。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"글쎄. 차라리 제대로 한 번 망하는 것도 나쁘진 않을 것 같은데.","JPN":"さあ？　いっそのこと完全に滅びてみるのも悪くないと思うけどね。","ENG":"I don't know, but it wouldn't be the worst for it to end.","TWN":"誰知道呢，不過世界要是真的毀滅了好像也不錯。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"난 항상 망하다 말아서 세상이 이 모양 이 꼴이라고 생각했거든.","JPN":"私は常々、滅亡が中途半端だから世界がこの様なんだと思ってたから。","ENG":"I've always thought this world is like this because it never goes through with the \\"ending\\" part.","TWN":"我一直覺得就是因為要死不活的，這個世界才會這麼糟糕。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 펠리세트.","JPN":"おい、フェリセット。","ENG":"Hey, Félicette.","TWN":"喂，費莉塞特。"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"갑자기 왜 불러요?","JPN":"なによ、急に。","ENG":"What?","TWN":"幹嘛突然叫我？"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어차피 망할 것 같으면…….","JPN":"どうせ滅ぶんなら……","ENG":"If the world's ending anyway...","TWN":"反正這個世界也要完蛋了……"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 전에 한탕 크게 벌여 볼래?","JPN":"その前に、大儲けしてみないか？","ENG":"Wanna go out with a bang?","TWN":"在那之前要不要跟我幹一票大的？"},"stage":{"bg":"CHARADE_006","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"Charade-Lotus Management Perimeter Zone\\n<color=#ffd34c>CSE Lv. 2</color>","TWN":"查雷德-洛德斯管理警戒區\\n<color=#ffd34c>CSE Lv.2</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저게…… 저게 대체 뭐야……?","JPN":"あ、あれは……何？","ENG":"What... is that?","TWN":"那……那到底是……什麼？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"여태까지 달의 뒷면에 저런 게 숨겨져 있었다고……?","JPN":"今まで月の裏側にあんなもんが隠れてたっていうの……？","ENG":"That was hiding behind the moon all this time...?","TWN":"到現在為止，月球背面竟然隱藏著那種東西……？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"태양은 지금 달에 의해 완전히 가려졌습니다.","JPN":"太陽は今、完全に月に隠れています。","ENG":"The sun is now completely obscured by the moon.","TWN":"太陽現在完全被月亮遮住了。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금 저 빛은 달의 뒷면이 스스로 발광하고 있는 거예요.","JPN":"今私たちが目にしているあの光は、月の裏側が自ら発光しているものです。","ENG":"The light from the moon's dark side is emitting on its own.","TWN":"現在那道光是月亮自己發出的光芒。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"믿기 힘들겠지만, 아마도 우리가 보고 있는 저것이 세피로트 나무의 일부…….","JPN":"信じがたいですが、おそらく私たちが見ているあれが、セフィロトの一部……","ENG":"It might be hard to believe, but what we are witnessing is a portion of the Tree of Sephiroth...","TWN":"難以置信，但也許我們看到的那東西是生命樹的一部分……"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>세피라</color>의 실체라고 할 수 있겠죠.","JPN":"<color=#ffd34c>セフィラ</color>の実体と言えるでしょう。","ENG":"The true form of <color=#ffd34c>Sephira</color>.","TWN":"說是<color=#ffd34c>塞菲拉</color>的實體也不過分吧。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저게 세피라라고……?","JPN":"あれが、セフィラ……？","ENG":"That's Sephira...?","TWN":"那就是塞菲拉……？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"달의 뒷면에서부터 에너지 반응……! 뭔가 온다……!","JPN":"月の裏側からエネルギー反応……！　何か来る……！","ENG":"Energy detected from the dark side of the moon...! It's headed this way...!","TWN":"月球背面出現了能量反應……！有什麼東西來了……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"차원에 균열이 일어날 정도의 막대한 에너지. 아마도 달과 지구를 잇는 경로겠군요.","JPN":"次元に亀裂が生じるほどの膨大なエネルギー。言うなれば、月と地球を繋げる経路、と呼ぶべきでしょう。","ENG":"A tremendous energy enough to create a rift in the dimension. It is probably a route connecting the moon and Earth.","TWN":"足以引發次元裂縫的巨大能量，大概能夠成為連接月球和地球的路徑……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"경로? 지금 그딴 뜬구름 잡는 소리 할 때야?","JPN":"経路？　今そんなこと言ってる場合じゃないって！","ENG":"A route? Now's not the time for nonsense!","TWN":"路徑？別再胡說八道了！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서 이제 뭘 어떻게 해야 되는 건데! 도망쳐야 하는 거 아니야!?","JPN":"それで何がどうなるの？　逃げないとやばいんじゃない？","ENG":"So, what do we do now?! Shouldn't we run?!","TWN":"所以現在該怎麼辦！難道不應該逃跑嗎！？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모릅니다.","JPN":"わかりません。","ENG":"I don’t know.","TWN":"我不知道。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_EARTHQUAKE"},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 이곳에서 일어나는 현상은 세계를 만드는 법칙에 의한 현실개변.","JPN":"今からここで起こる現象は、世界を作る法則による現実改変。","ENG":"What's happening from here on out is a change in reality by the law of creating a world.","TWN":"從現在開始，這裡發生的現象是由創造世界的法則所引起的現實變異。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하나부터 열까지 전부 미지의 영역이에요.","JPN":"一から十まで、未知の領域です。","ENG":"Everything, from start to finish, is unknown.","TWN":"從一到十，都是未知領域。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"제길! 그딴 걸 말이라고 해!?","JPN":"くっそ！　そんな説明はいらないんだよ！","ENG":"Dammit! You can't be serious!","TWN":"混蛋！你這算什麼話！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어차피 피하기에는 늦었어!","JPN":"どうせ逃げるにはもう遅いってば！","ENG":"It's too late to run away now!","TWN":"反正已經來不及躲開了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뒤로 물러나……!!","JPN":"後ろに下がっ……！！","ENG":"Get back–!","TWN":"退後……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"……크윽. 어떻게든 버텨냈나?","JPN":"………くっ。なんとか耐えられた……？","ENG":"...Ugh. Are we still alive?","TWN":"……咳咳。總算撐住了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 스완! 괜찮아?","JPN":"おい、スワン！　大丈夫？","ENG":"Hey, Swan! Are you okay?","TWN":"喂，史旺！沒事嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 괜찮아요. 리트리버.","JPN":"私は大丈夫ですよ、レトリーバー。","ENG":"I'm fine, retriever.","TWN":"我沒事，獵犬。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무래도 여긴 달로부터 연결되었던 빛 기둥의 중심지에서 조금 벗어나 있던 모양이로군요.","JPN":"どうやらここは、月から繋がっていた光の柱の中心部から少しずれていたようですね。","ENG":"It seems that this place was slightly off centered from the pillar of light connecting to the moon.","TWN":"看來這裡稍微偏離了從月亮連接過來的光柱中心地帶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하여간 재수없긴. 고마울 땐 고맙다고 하면 어디 덧나나?","JPN":"嫌なやつだね。こういう時はお礼とか言ったらどう？","ENG":"You're so annoying. Can't you just say \\"thank you\\"?","TWN":"真討厭，感激的時候說聲謝謝會死嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서 여긴 어디야?","JPN":"で、ここはどこ？","ENG":"So? Where are we?","TWN":"呃？所以這裡是哪裡？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아까 그 거대한 차원 균열에 휩쓸려 버린건가? 미아 신세는 질색인데.","JPN":"さっきの巨大な次元の亀裂に巻き込まれちゃったのかな？　迷子になるのはごめんだけど。","ENG":"Did we get swept away by that huge dimensional rift? I really don't want to end up on a missing person's poster.","TWN":"被剛才那個巨大的次元裂縫捲走了嗎？我可不想流落街頭。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 우린 차원 이동 같은 걸 한 게 아니에요.","JPN":"いいえ、私たちが次元を移動したわけではありません。","ENG":"No. We didn't cross dimensions.","TWN":"不，我們並沒有進行次元移動之類的事情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우리를 둘러싸고 있는 이곳 세계가 변한 겁니다.","JPN":"私たちをめぐる世界が変わったのです。","ENG":"It's just that the world around us has changed.","TWN":"我們所處的這個世界已經變了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 이곳이 우리가 있었던 침식지대였다고?","JPN":"ってことは、ここがさっきまでいたあの侵食地帯ってこと？","ENG":"Then, this used to be the Corrupted Area we were in?","TWN":"那這裡還是我們原先所在的侵蝕地區？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저기 언덕을 보세요. 우리가 있던 곳과 지형적인 특징은 변하지 않았어요.","JPN":"あちらの丘を見てください。地形的な特徴はそのままです。","ENG":"Look at that hill. The location and topographical characteristics of this place haven't changed.","TWN":"看那邊遠處的山丘，地形特徵沒有改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무래도 세피라의 영향으로 인해, 이 주변 환경이 전부 뒤바뀐 모양이네요.","JPN":"どうやらセフィラの影響で、この辺りの環境が変化したようですね。","ENG":"It seems that the environment around us has changed due to Sephira's influence.","TWN":"看來是受到了塞菲拉的影響，僅是周圍的環境改變了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"침식파에 오랫동안 노출된 땅은 회복하는데 많은 시간이 걸린다고.","JPN":"ずっと侵食波にさらされていた土地は、回復にもすごい時間がかかるんだけど。","ENG":"It takes a long time to recover land exposed to Corruption rays for a long time, you know.","TWN":"長時間暴露在侵蝕波下的土地原本需要很長時間才能恢復。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"세피라라는 게 이 일대의 자연 환경을 전부 회복시켰다는 거야?","JPN":"セフィラってのが、この一帯の自然環境を全部回復させたっていうの？","ENG":"So, you're telling me that this Sephira fully restored the entire natural environment of this place?","TWN":"你是說塞菲拉恢復了這一帶的自然環境？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래대로 회복시킨 것인지, 새롭게 창조한 것인지 분명하지는 않지만…….","JPN":"元通りに回復させたのか、新たに造り上げたのかは不明ですが……","ENG":"I'm not sure if it was restored to its original state, or if it was created anew, but...","TWN":"不確定是恢復了原貌，還是重新創造出了新的環境……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애석하게도 그게 전부는 아닌 모양이네요.","JPN":"残念ながら、それだけではないようですね。","ENG":"that doesn't seem to be all of it, unfortunately.","TWN":"可惜這還不是全部呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"음? 이 소리는……?","JPN":"うん？　この音は……","ENG":"Hmm? What was that sound...?","TWN":"嗯？這聲音是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르, 그르르으…….","JPN":"グルル、グルルル……","ENG":"Grr... Grrrrrrr...","TWN":"呃嗚嗚嗚嗚……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L44_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저건 침식체……?","JPN":"あれは、侵食体……？","ENG":"Isn't that...a C.O....?","TWN":"那是侵蝕體……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export